import{_ as a,o as l,c as e,a4 as s}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"现代文主观题答题公式","description":"","frontmatter":{},"headers":[],"relativePath":"chinese/tip-reading.md","filePath":"chinese/tip-reading.md"}'),i={name:"chinese/tip-reading.md"};function n(r,t,o,p,d,h){return l(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="现代文主观题答题公式" tabindex="-1">现代文主观题答题公式 <a class="header-anchor" href="#现代文主观题答题公式" aria-label="Permalink to &quot;现代文主观题答题公式&quot;">​</a></h1><p><strong>从&quot;答不到点&quot;到&quot;踩中得分点&quot;——现代文阅读答题套路</strong></p><hr><h2 id="痛点" tabindex="-1">痛点 <a class="header-anchor" href="#痛点" aria-label="Permalink to &quot;痛点&quot;">​</a></h2><ul><li>知道大概意思，但不知道怎么组织语言</li><li>写了很多，但不得分</li><li>不知道要答几点，答多还是答少</li></ul><hr><h2 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h2><h3 id="原则1-看分给点" tabindex="-1">原则1：看分给点 <a class="header-anchor" href="#原则1-看分给点" aria-label="Permalink to &quot;原则1：看分给点&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">分值</th><th style="text-align:center;">答几点</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:center;">2分</td><td style="text-align:center;">1-2点</td><td style="text-align:left;">答出核心意思</td></tr><tr><td style="text-align:center;">4分</td><td style="text-align:center;">2-4点</td><td style="text-align:left;">每点1-2分</td></tr><tr><td style="text-align:center;">6分</td><td style="text-align:center;">3-6点</td><td style="text-align:left;">多角度回答</td></tr></tbody></table><h3 id="原则2-用术语" tabindex="-1">原则2：用术语 <a class="header-anchor" href="#原则2-用术语" aria-label="Permalink to &quot;原则2：用术语&quot;">​</a></h3><p><strong>不要</strong>：用自己的大白话 <strong>要</strong>：使用语文专业术语</p><p><strong>常用术语库</strong>：</p><ul><li>结构类：铺垫、照应、承上启下、总领全文、总结全文</li><li>手法类：比喻、拟人、对比、象征、伏笔、悬念</li><li>效果类：生动形象、突出强调、营造氛围、引发思考</li></ul><h3 id="原则3-分角度" tabindex="-1">原则3：分角度 <a class="header-anchor" href="#原则3-分角度" aria-label="Permalink to &quot;原则3：分角度&quot;">​</a></h3><p>一个题目的多个角度：</p><ul><li>内容角度（写了什么）</li><li>结构角度（在文中的位置作用）</li><li>手法角度（用了什么技巧）</li><li>情感角度（表达什么情感/主旨）</li></ul><hr><h2 id="五大题型公式" tabindex="-1">五大题型公式 <a class="header-anchor" href="#五大题型公式" aria-label="Permalink to &quot;五大题型公式&quot;">​</a></h2><h3 id="题型1-含义理解题" tabindex="-1">题型1：含义理解题 <a class="header-anchor" href="#题型1-含义理解题" aria-label="Permalink to &quot;题型1：含义理解题&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>&quot;×××&quot;这句话有什么含义？</li><li>如何理解&quot;×××&quot;？</li></ul><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>表层含义（字面意思）+ 深层含义（象征/情感/主旨）</span></span></code></pre></div><p><strong>示例</strong>：</p><blockquote><p>&quot;父亲的背影&quot;在文中多次出现，含义是什么？</p></blockquote><p><strong>答案</strong>：</p><ul><li>表层：父亲离别时的背影形象</li><li>深层：象征着父亲深沉的爱，以及作者对父亲的思念与愧疚</li></ul><hr><h3 id="题型2-作用分析题-⭐" tabindex="-1">题型2：作用分析题 ⭐ <a class="header-anchor" href="#题型2-作用分析题-⭐" aria-label="Permalink to &quot;题型2：作用分析题 ⭐&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>某段有什么作用？</li><li>某句在文中起什么作用？</li><li>作者为什么要写×××？</li></ul><p><strong>公式（从三个角度答）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 内容角度：写了什么，表现了什么</span></span>
<span class="line"><span>② 结构角度：与上下文的关系（照应、铺垫、过渡等）</span></span>
<span class="line"><span>③ 手法/效果角度：用了什么手法，有什么效果</span></span></code></pre></div><p><strong>结构作用词汇</strong>：</p><ul><li>开头段：总领全文、奠定基调、引出下文、设置悬念</li><li>中间段：承上启下、过渡、照应、铺垫</li><li>结尾段：总结全文、点明主旨、升华主题、照应开头</li></ul><p><strong>示例</strong>：</p><blockquote><p>文章第一段描写故乡的景色，有什么作用？</p></blockquote><p><strong>答案</strong>：</p><ul><li>内容上：描写了故乡宁静美丽的景色，营造了温馨的氛围</li><li>结构上：引出下文对童年生活的回忆，为全文奠定怀旧的基调</li><li>手法上：运用景物描写，情景交融，增强了文章的感染力</li></ul><hr><h3 id="题型3-手法赏析题-⭐" tabindex="-1">题型3：手法赏析题 ⭐ <a class="header-anchor" href="#题型3-手法赏析题-⭐" aria-label="Permalink to &quot;题型3：手法赏析题 ⭐&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>赏析文中划线句子</li><li>某句运用了什么手法？有什么效果？</li><li>文章在表达上有什么特色？</li></ul><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>手法 + 分析（怎么用的）+ 效果（生动形象地写出了...）+ 情感</span></span></code></pre></div><p><strong>常见手法及效果</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">手法</th><th style="text-align:left;">效果词</th></tr></thead><tbody><tr><td style="text-align:center;">比喻</td><td style="text-align:left;">生动形象</td></tr><tr><td style="text-align:center;">拟人</td><td style="text-align:left;">生动活泼，亲切自然</td></tr><tr><td style="text-align:center;">对比</td><td style="text-align:left;">突出强调，鲜明有力</td></tr><tr><td style="text-align:center;">排比</td><td style="text-align:left;">增强气势，节奏感强</td></tr><tr><td style="text-align:center;">设问</td><td style="text-align:left;">引发思考，吸引读者</td></tr><tr><td style="text-align:center;">反问</td><td style="text-align:left;">加强语气，引人深思</td></tr><tr><td style="text-align:center;">细节描写</td><td style="text-align:left;">细腻传神，如在眼前</td></tr><tr><td style="text-align:center;">环境描写</td><td style="text-align:left;">渲染气氛，烘托心情</td></tr></tbody></table><p><strong>示例</strong>：</p><blockquote><p>赏析：&quot;他的眼里闪烁着泪光，像秋夜的星星。&quot;</p></blockquote><p><strong>答案</strong>：</p><ul><li>运用了比喻的修辞手法</li><li>把眼里的泪光比作秋夜的星星</li><li>生动形象地写出了人物内心的激动与悲伤</li><li>表达了人物复杂的情感</li></ul><hr><h3 id="题型4-概括归纳题" tabindex="-1">题型4：概括归纳题 <a class="header-anchor" href="#题型4-概括归纳题" aria-label="Permalink to &quot;题型4：概括归纳题&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>文章主要写了什么？</li><li>某人的性格特点有哪些？</li><li>作者的观点是什么？</li></ul><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分层概括 + 提炼要点</span></span></code></pre></div><p><strong>技巧</strong>：</p><ul><li>找关键句（段首、段尾、过渡句）</li><li>合并同类项</li><li>用简洁语言概括</li></ul><p><strong>示例</strong>：</p><blockquote><p>概括文章中父亲的形象特点。</p></blockquote><p><strong>答案</strong>：</p><ul><li>勤劳朴实：从&quot;每天天不亮就起床劳作&quot;可见</li><li>沉默寡言：从&quot;很少说话，只是默默做事&quot;可见</li><li>深爱子女：从&quot;把最好的留给孩子&quot;可见</li></ul><hr><h3 id="题型5-探究评价题" tabindex="-1">题型5：探究评价题 <a class="header-anchor" href="#题型5-探究评价题" aria-label="Permalink to &quot;题型5：探究评价题&quot;">​</a></h3><p><strong>问法</strong>：</p><ul><li>你同意作者的观点吗？为什么？</li><li>结合文本，谈谈你的看法。</li><li>文章给了你什么启示？</li></ul><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>观点 + 文本依据 + 个人理解/现实联系</span></span></code></pre></div><p><strong>注意</strong>：</p><ul><li>观点要明确（同意/不同意/辩证看待）</li><li>必须有文本依据（引用原文或概括）</li><li>可以联系现实，但不要脱离文本</li></ul><hr><h2 id="答题格式规范" tabindex="-1">答题格式规范 <a class="header-anchor" href="#答题格式规范" aria-label="Permalink to &quot;答题格式规范&quot;">​</a></h2><h3 id="分点作答" tabindex="-1">分点作答 <a class="header-anchor" href="#分点作答" aria-label="Permalink to &quot;分点作答&quot;">​</a></h3><p><strong>不要</strong>：写成一团 <strong>要</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① ...</span></span>
<span class="line"><span>② ...</span></span>
<span class="line"><span>③ ...</span></span></code></pre></div><h3 id="先概括后分析" tabindex="-1">先概括后分析 <a class="header-anchor" href="#先概括后分析" aria-label="Permalink to &quot;先概括后分析&quot;">​</a></h3><p><strong>不要</strong>：直接抄原文 <strong>要</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>（概括）这句话运用了比喻手法，</span></span>
<span class="line"><span>（分析）把A比作B，</span></span>
<span class="line"><span>（效果）生动形象地写出了C，</span></span>
<span class="line"><span>（情感）表达了D情感。</span></span></code></pre></div><hr><h2 id="检查清单" tabindex="-1">检查清单 <a class="header-anchor" href="#检查清单" aria-label="Permalink to &quot;检查清单&quot;">​</a></h2><p>答题前问自己：</p><ul><li>[ ] 分值多少？要答几点？</li><li>[ ] 用了专业术语吗？</li><li>[ ] 分角度了吗？（内容/结构/手法/情感）</li><li>[ ] 分点作答了吗？</li></ul><hr><p><strong>文档编号</strong>: Chin-Tip-002<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,85)])])}const u=a(i,[["render",n]]);export{g as __pageData,u as default};
